<?php
 namespace League\CommonMark\Extension\Mention; use League\CommonMark\Inline\Element\Link; use League\CommonMark\Inline\Element\Text; class Mention extends Link { private $symbol; private $identifier; public function __construct(string $symbol, string $identifier, string $label = null) { $this->symbol = $symbol; $this->identifier = $identifier; parent::__construct('', $label ?? \sprintf('%s%s', $symbol, $identifier)); } public function getLabel(): ?string { if (($labelNode = $this->findLabelNode()) === null) { return null; } return $labelNode->getContent(); } public function getIdentifier(): string { return $this->identifier; } public function getSymbol(): string { return $this->symbol; } public function hasUrl(): bool { return !empty($this->url); } public function setLabel(string $label): self { if (($labelNode = $this->findLabelNode()) === null) { $labelNode = new Text(); $this->prependChild($labelNode); } $labelNode->setContent($label); return $this; } private function findLabelNode(): ?Text { foreach ($this->children() as $child) { if ($child instanceof Text) { return $child; } } return null; } } 